<section class="v4-page-shell"><div class="v4-page-head"><h1>SEO Preview Center</h1><p>معاينة SEO وحفظ overrides مخصصة.</p></div>
<?php if (!empty($flash)): ?><div class="v4-flash v4-flash-<?= e($flash['type'] ?? 'info') ?>"><?= e($flash['message'] ?? '') ?></div><?php endif; ?>
<form class="v4-search-form" method="get" action="<?= e(godyar_v4_base_url('/v4/admin/seo-preview')) ?>"><select name="type"><?php foreach(['news'=>'News','page'=>'Page','category'=>'Category'] as $v=>$l): ?><option value="<?= e($v) ?>" <?= (($preview['type'] ?? '') === $v) ? 'selected' : '' ?>><?= e($l) ?></option><?php endforeach; ?></select><input type="text" name="slug" placeholder="slug أو id" value="<?= e($preview['identifier'] ?? '') ?>"><select name="lang"><?php foreach(['ar','en','fr'] as $lang): ?><option value="<?= e($lang) ?>"><?= e($lang) ?></option><?php endforeach; ?></select><button type="submit">معاينة</button></form>
<div class="v4-seo-preview-grid"><section class="v4-seo-card"><h2>Preview</h2><div class="v4-seo-serp"><strong><?= e($preview['meta']['title'] ?? '') ?></strong><span><?= e($preview['meta']['canonical'] ?? '') ?></span><p><?= e($preview['meta']['description'] ?? '') ?></p></div><pre class="v4-pretty-box"><?= e(json_encode($preview['meta']['json_ld'] ?? [], JSON_UNESCAPED_UNICODE | JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES)) ?></pre></section><section class="v4-seo-card"><h2>Checks</h2><ul class="v4-check-list"><?php foreach (($preview['checks'] ?? []) as $check): ?><li class="v4-check-<?= e($check['status'] ?? 'ok') ?>"><strong><?= e($check['label'] ?? '') ?>:</strong> <?= e($check['message'] ?? '') ?></li><?php endforeach; ?></ul></section></div>
<section class="v4-seo-card"><h2>SEO Override</h2><form class="v4-stack-form" method="post" action="<?= e(godyar_v4_base_url('/v4/admin/seo-preview/save')) ?>"><?= godyar_v4_csrf_field() ?><input type="hidden" name="type" value="<?= e($preview['type'] ?? 'news') ?>"><input type="hidden" name="lang" value="ar"><input type="hidden" name="identifier" value="<?= e(($preview['record']['slug'] ?? $preview['record']['id'] ?? $preview['identifier'] ?? '')) ?>"><label>Title<input type="text" name="title" value="<?= e($preview['meta']['override']['title'] ?? $preview['meta']['title'] ?? '') ?>"></label><label>Description<textarea name="description" rows="3"><?= e($preview['meta']['override']['description'] ?? $preview['meta']['description'] ?? '') ?></textarea></label><label>Canonical<input type="text" name="canonical" value="<?= e($preview['meta']['override']['canonical'] ?? $preview['meta']['canonical'] ?? '') ?>"></label><label>OG image<input type="text" name="og_image" value="<?= e($preview['meta']['override']['og_image'] ?? $preview['meta']['og_image'] ?? '') ?>"></label><label>Robots<input type="text" name="robots" value="<?= e($preview['meta']['override']['robots'] ?? $preview['meta']['robots'] ?? '') ?>"></label><button type="submit">حفظ override</button></form></section></section>
